parameters.jsCode:
// Extract the complexity and chosen model from classifier
const classifyResult = $json;
const complexity = classifyResult.complexity || 'complex';
const chosenModel = classifyResult.model || 'anthropic/claude-sonnet-4-6';
const agentForModel = chosenModel.includes('haiku') ? 'automation' : 'fredrick';

return [{
  json: {
    complexity,
    chosenModel,
    agentForModel,
    prompt: $json.prompt || $input.all()[0].json.message || '',
    sessionKey: $input.all()[0].json._openclaw?.sessionKey || $input.all()[0].json.sessionKey || ''
  }
}];

parameters.jsonBody:
={{ JSON.stringify({
  tool: 'sessions_send',
  args: {
    sessionKey: $json.sessionKey,
    message: $json.prompt
  },
  _openclaw: { agentId: $json.agentForModel }
}) }}

