// Build callback response with routing info
const agentResponse = $json.result || $json;
const complexity = $input.all()[1].json.complexity;
const chosenModel = $input.all()[1].json.chosenModel;

return [{
  json: {
    result: agentResponse,
    summary: `Routed to ${chosenModel} (${complexity})`,
    routingDecision: {
      complexity,
      model: chosenModel,
      agent: $input.all()[1].json.agentForModel
    }
  }
}];
